import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.provider.OpenableColumns;
import android.util.Log;
import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import com.github.barteksc.pdfviewer.PDFView;
import com.github.barteksc.pdfviewer.scroll.DefaultScrollHandle;
import java.io.File;

public class DocumentViewerActivity extends AppCompatActivity {

    private static final String TAG = "DocumentViewerActivity";
    private PDFView pdfView;
    private File file;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);

        pdfView = findViewById(R.id.pdfView);

        Intent intent = getIntent();
        if (Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri uri = intent.getData();
            if (uri != null) {
                String mime = getContentResolver().getType(uri);
                if ("application/pdf".equals(mime)) {
                    displayPdfFile(uri);
                } else if (mime.startsWith("image/")) {
                    displayImageFile(uri);
                }
            }
        }
    }

    private void displayPdfFile(Uri uri) {
        pdfView.fromUri(uri)
               .scrollHandle(new DefaultScrollHandle(this))
               .load();
    }

    private void displayImageFile(Uri uri) {
        // Handle image file display here
        // You can use libraries like Glide or Picasso to load the image
    }
}